using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3.0) = 4
            Assert.Equal(3, list.Count);
        }

        [Theory]
        [InlineData(1, false)]
        [InlineData(2, true)]
        [InlineData(5, true)]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), 50, pageIndex, 10);

            Assert.Equal(expected, list.HasPreviousPage);
        }

        [Theory]
        [InlineData(1, 10, 30, true)]   // page 1 of 3
        [InlineData(3, 10, 30, false)]  // page 3 of 3
        [InlineData(1, 10, 5, false)]   // single page
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int pageSize, int count, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

            Assert.Equal(expected, list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(new[] { 6, 7, 8, 9, 10 }, result.ToArray());
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(new[] { 1, 2, 3, 4, 5 }, result.ToArray());
        }

        [Fact]
        public void Create_LastPartialPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 13).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(3, result.PageIndex);
            Assert.Equal(new[] { 11, 12, 13 }, result.ToArray());
        }
    }
}

