using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests
    {
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;

        public CoursesControllerTests()
        {
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
            _mockEnv.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
            _mockLogger = new Mock<ILogger<CoursesController>>();
        }

        private (CoursesController controller, SchoolContext context) CreateControllerWithData()
        {
            var context = TestDbContext.Create();
            var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var department = new Department { Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructor.ID };
            context.Departments.Add(department);
            context.SaveChanges();

            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = department.DepartmentID },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = department.DepartmentID }
            );
            context.SaveChanges();

            var controller = new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
            return (controller, context);
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Index() as ViewResult;

                Assert.NotNull(result);
                var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
                Assert.Equal(2, model.Count);
            }
        }

        // --- Details ---

        [Fact]
        public void Details_WithValidId_ReturnsCourse()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Details(1050) as ViewResult;

                Assert.NotNull(result);
                var model = Assert.IsType<Course>(result.Model);
                Assert.Equal("Chemistry", model.Title);
            }
        }

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Details(null) as StatusCodeResult;

                Assert.NotNull(result);
                Assert.Equal(400, result.StatusCode);
            }
        }

        // --- Create ---

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentList()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Create() as ViewResult;

                Assert.NotNull(result);
                Assert.NotNull(controller.ViewBag.DepartmentID);
                Assert.IsType<Course>(result.Model);
            }
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var dept = context.Departments.First();
                var course = new Course { CourseID = 9999, Title = "New Course", Credits = 3, DepartmentID = dept.DepartmentID };

                var result = controller.Create(course, null) as RedirectToActionResult;

                Assert.NotNull(result);
                Assert.Equal("Index", result.ActionName);
                Assert.Equal(3, context.Courses.Count());
            }
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var (controller, context) = CreateControllerWithData();
