using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests
    {
        private (DepartmentsController controller, SchoolContext context) CreateControllerWithData()
        {
            var context = TestDbContext.Create();
            var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            context.Departments.AddRange(
                new Department { Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructor.ID },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01") }
            );
            context.SaveChanges();

            var controller = new DepartmentsController(context);
            return (controller, context);
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithAllDepartments()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Index() as ViewResult;

                Assert.NotNull(result);
                var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
                Assert.Equal(2, model.Count);
            }
        }

        // --- Details ---

        [Fact]
        public void Details_WithValidId_ReturnsDepartment()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var dept = context.Departments.First();

                var result = controller.Details(dept.DepartmentID) as ViewResult;

                Assert.NotNull(result);
                var model = Assert.IsType<Department>(result.Model);
                Assert.Equal(dept.Name, model.Name);
            }
        }

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Details(null) as StatusCodeResult;

                Assert.NotNull(result);
                Assert.Equal(400, result.StatusCode);
            }
        }

        [Fact]
        public void Details_WithInvalidId_ReturnsNotFound()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Details(999);

                Assert.IsType<NotFoundResult>(result);
            }
        }

        // --- Create ---

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorList()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Create() as ViewResult;

                Assert.NotNull(result);
                Assert.NotNull(controller.ViewBag.InstructorID);
            }
        }

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var department = new Department { Name = "Physics", Budget = 200000, StartDate = DateTime.Parse("2020-01-01") };

                var result = controller.Create(department) as RedirectToActionResult;

                Assert.NotNull(result);
                Assert.Equal("Index", result.ActionName);
                Assert.Equal(3, context.Departments.Count());
            }
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                controller.ModelState.AddModelError("Name", "Required");
                var department = new Department();

                var result = controller.Create(department) as ViewResult;

                Assert.NotNull(result);
                Assert.NotNull(controller.ViewBag.InstructorID);
            }
        }

        // --- Edit ---

        [Fact]
        public void Edit_Get_WithValidId_ReturnsDepartment()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var dept = context.Departments.First();

                var result = controller.Edit(dept.DepartmentID) as ViewResult;

                Assert.NotNull(result);
                var model = Assert.IsType<Department>(result.Model);
                Assert.Equal(dept.Name, model.Name);
                Assert.NotNull(controller.ViewBag.InstructorID);
            }
        }

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Edit(null) as StatusCodeResult;

                Assert.NotNull(result);
                Assert.Equal(400, result.StatusCode);
            }
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Edit(999);

                Assert.IsType<NotFoundResult>(result);
            }
        }

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var dept = context.Departments.First();
                context.Entry(dept).State = EntityState.Detached;

                var edited = new Department
                {
                    DepartmentID = dept.DepartmentID,
                    Name = "Updated Engineering",
                    Budget = 999999,
                    StartDate = dept.StartDate,
                    RowVersion = dept.RowVersion
                };

                var result = controller.Edit(edited) as RedirectToActionResult;

                Assert.NotNull(result);
                Assert.Equal("Index", result.ActionName);
            }
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                controller.ModelState.AddModelError("Name", "Required");
                var department = new Department { DepartmentID = 1 };

                var result = controller.Edit(department) as ViewResult;

                Assert.NotNull(result);
                Assert.NotNull(controller.ViewBag.InstructorID);
            }
        }

        // --- Delete ---

        [Fact]
        public void Delete_Get_WithValidId_ReturnsDepartment()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var dept = context.Departments.First();

                var result = controller.Delete(dept.DepartmentID) as ViewResult;

                Assert.NotNull(result);
                var model = Assert.IsType<Department>(result.Model);
                Assert.Equal(dept.Name, model.Name);
            }
        }

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Delete(null) as StatusCodeResult;

                Assert.NotNull(result);
                Assert.Equal(400, result.StatusCode);
            }
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Delete(999);

                Assert.IsType<NotFoundResult>(result);
            }
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var dept = context.Departments.First();

                var result = controller.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

                Assert.NotNull(result);
                Assert.Equal("Index", result.ActionName);
                Assert.Single(context.Departments);
            }
        }
    }
}
