using System;
using System.Collections.Generic;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests
    {
        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = TestDbContext.Create();
            var controller = new HomeController(context);

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsEnrollmentDateGroups()
        {
            using var context = TestDbContext.Create();
            context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "One", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { FirstMidName = "B", LastName = "Two", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { FirstMidName = "C", LastName = "Three", EnrollmentDate = DateTime.Parse("2012-09-01") }
            );
            context.SaveChanges();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void About_EmptyDatabase_ReturnsEmptyList()
        {
            using var context = TestDbContext.Create();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void Contact_SetsViewBagMessage()
        {
            using var context = TestDbContext.Create();
            var controller = new HomeController(context);

            var result = controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            using var context = TestDbContext.Create();
            var controller = new HomeController(context);

            var result = controller.Error();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_SetsPermissionMessage()
        {
            using var context = TestDbContext.Create();
            var controller = new HomeController(context);

            var result = controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("You don't have permission to access this resource.", controller.ViewBag.Message);
        }
    }
}

