using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests
    {
        private static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") }
            );
            context.SaveChanges();
        }

        // --- Index tests ---

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            using var context = TestDbContext.Create();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDesc_OrdersByLastNameDescending()
        {
            using var context = TestDbContext.Create();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Anand", model[0].LastName);
            Assert.Equal("Alexander", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            using var context = TestDbContext.Create();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(DateTime.Parse("2010-09-01"), model[0].EnrollmentDate);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            using var context = TestDbContext.Create();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(DateTime.Parse("2013-09-01"), model[0].EnrollmentDate);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersCorrectly()
        {
            using var context = TestDbContext.Create();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Alexander", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersCorrectly()
        {
            using var context = TestDbContext.Create();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Carson", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_NewSearch_SetsCurrentFilter()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);

            controller.Index(null, null, "test", null);

            Assert.Equal("test", controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_NoNewSearch_UsesCurrentFilter()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);

            controller.Index(null, "existing", null, null);

            Assert.Equal("existing", controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_SetsSortParameters()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);

            controller.Index(null, null, null, null);

            Assert.Equal("name_desc", controller.ViewBag.NameSortParm);
            Assert.Equal("Date", controller.ViewBag.DateSortParm);
        }

        // --- Details tests ---

        [Fact]
        public void Details_WithValidId_ReturnsStudent()
        {
            using var context = TestDbContext.Create();
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Today };
            context.Students.Add(student);
            context.SaveChanges();
            var controller = new StudentsController(context);

            var result = controller.Details(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Carson", model.FirstMidName);
        }

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        // --- Create tests ---

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var result = controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(context.Students);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student { FirstMidName = "New", EnrollmentDate = DateTime.Parse("2020-09-01") };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Empty(context.Students);
        }

        [Fact]
        public void Create_Post_MinDateValue_AddsModelError()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // --- Edit tests ---

        [Fact]
        public void Edit_Get_WithValidId_ReturnsStudent()
        {
            using var context = TestDbContext.Create();
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Today };
            context.Students.Add(student);
            context.SaveChanges();
            var controller = new StudentsController(context);

            var result = controller.Edit(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Carson", model.FirstMidName);
        }

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_WithInvalidId_ReturnsNotFound()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);

            var result = controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            using var context = TestDbContext.Create();
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") };
            context.Students.Add(student);
            context.SaveChanges();
            context.Entry(student).State = EntityState.Detached;

            var controller = new StudentsController(context);
            var editedStudent = new Student
            {
                ID = student.ID,
                FirstMidName = "Updated",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var result = controller.Edit(editedStudent) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_MinDateValue_AddsModelError()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        // --- Delete tests ---

        [Fact]
        public void Delete_Get_WithValidId_ReturnsStudent()
        {
            using var context = TestDbContext.Create();
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Today };
            context.Students.Add(student);
            context.SaveChanges();
            var controller = new StudentsController(context);

            var result = controller.Delete(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal("Carson", model.FirstMidName);
        }

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            using var context = TestDbContext.Create();
            var controller = new StudentsController(context);

            var result = controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            using var context = TestDbContext.Create();
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Today };
            context.Students.Add(student);
            context.SaveChanges();
            var controller = new StudentsController(context);

            var result = controller.DeleteConfirmed(student.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Empty(context.Students);
        }
    }
}

