                Assert.NotNull(result);
                Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
            }
        }

        [Fact]
        public void Create_Post_ValidImage_SavesCourseWithImagePath()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var dept = context.Departments.First();
                var course = new Course { CourseID = 8888, Title = "Art", Credits = 2, DepartmentID = dept.DepartmentID };
                var mockFile = new Mock<IFormFile>();
                mockFile.Setup(f => f.FileName).Returns("material.png");
                mockFile.Setup(f => f.Length).Returns(1024);
                mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()));

                var result = controller.Create(course, mockFile.Object) as RedirectToActionResult;

                Assert.NotNull(result);
                Assert.Equal("Index", result.ActionName);
                var saved = context.Courses.Find(8888);
                Assert.NotNull(saved);
                Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
            }
        }

        // --- Edit ---

        [Fact]
        public void Edit_Get_WithValidId_ReturnsCourse()
        {
            var (controller, context) = CreateControllerWithData();
            using (context)
            {
                var result = controller.Edit(1050) as ViewResult;

