namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests
    {
        private SchoolContext CreateSeededContext()
        {
            var context = TestDbContext.Create();

            var instructor1 = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };
            var instructor2 = new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            var department = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor1.ID
            };
            context.Departments.Add(department);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = department.DepartmentID,
                Enrollments = new List<Enrollment>()
            };
            context.Courses.Add(course);
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor1.ID, CourseID = course.CourseID });
            context.SaveChanges();

            return context;
        }

        // --- Index ---

        [Fact]
        public void Index_NoSelection_ReturnsAllInstructors()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            using var context = CreateSeededContext();
            var instructor = context.Instructors.First(i => i.LastName == "Abercrombie");
            var controller = new InstructorsController(context);

            var result = controller.Index(instructor.ID, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
            Assert.Equal("Chemistry", model.Courses.First().Title);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            var names = model.Instructors.Select(i => i.LastName).ToList();
            Assert.Equal("Abercrombie", names[0]);
            Assert.Equal("Fakhouri", names[1]);
        }

        // --- Details ---

        [Fact]
        public void Details_WithValidId_ReturnsInstructor()
        {
            using var context = CreateSeededContext();
            var instructor = context.Instructors.First();
            var controller = new InstructorsController(context);

            var result = controller.Details(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.FirstMidName, model.FirstMidName);
        }

        [Fact]
        public void Details_WithNullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_WithInvalidId_ReturnsNotFound()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        // --- Create ---

        [Fact]
        public void Create_Get_ReturnsViewWithCourseData()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(3, context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_CreatesCourseAssignments()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = controller.Create(instructor, new[] { "1050" }) as RedirectToActionResult;

            Assert.NotNull(result);
            var savedInstructor = context.Instructors.First(i => i.LastName == "Instructor");
            Assert.Single(context.CourseAssignments.Where(ca => ca.InstructorID == savedInstructor.ID));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_WithValidId_ReturnsInstructor()
        {
            using var context = CreateSeededContext();
            var instructor = context.Instructors.First(i => i.LastName == "Abercrombie");
            var controller = new InstructorsController(context);

            var result = controller.Edit(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Kim", model.FirstMidName);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void Edit_Get_WithNullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        // --- Delete ---

        [Fact]
        public void Delete_Get_WithValidId_ReturnsInstructor()
        {
            using var context = CreateSeededContext();
            var instructor = context.Instructors.First();
            var controller = new InstructorsController(context);

            var result = controller.Delete(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructor.LastName, model.LastName);
        }

        [Fact]
        public void Delete_Get_WithNullId_ReturnsBadRequest()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_WithInvalidId_ReturnsNotFound()
        {
            using var context = CreateSeededContext();
            var controller = new InstructorsController(context);

            var result = controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            using var context = CreateSeededContext();
            var instructor = context.Instructors.First(i => i.LastName == "Fakhouri");
            var controller = new InstructorsController(context);

            var result = controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(context.Instructors);
        }

        [Fact]
        public void DeleteConfirmed_UnlinksDepartmentAdministrator()
        {
            using var context = CreateSeededContext();
            var instructor = context.Instructors.First(i => i.LastName == "Abercrombie");
            var controller = new InstructorsController(context);

            controller.DeleteConfirmed(instructor.ID);

            var dept = context.Departments.First(d => d.Name == "Engineering");
            Assert.Null(dept.InstructorID);
        }
    }
}

